function fixUrl(url) {
  if (!url) return null;

  if (url.startsWith("/app/")) {
    return `${baseUrl}/files/${url.replace("/app/", "")}`;
  }

  if (url.startsWith("/")) {
    return `${baseUrl}${url}`;
  }

  return url;
}

function cleanBase64(value) {
  if (!value || typeof value !== "string") return null;

  if (value.includes(",")) {
    return value.split(",").pop().replace(/\s/g, "");
  }

  return value.replace(/\s/g, "");
}

function getImageUrl(result, index = 0) {
  if (!result) return null;

  const direct =
    result.heatmap_image_url ||
    result.explanation_image_url ||
    result.image_url ||
    result.output_image_url ||
    result.result_image_url;

  if (direct) return fixUrl(direct);

  const visualizations = result.visualizations || [];
  return fixUrl(visualizations[index]?.image_url);
}

