  if (!result) return null;

  const direct =
    result.heatmap_image_base64 ||
    result.explanation_image_base64 ||
    result.image_base64 ||
    result.output_image_base64 ||
    result.result_image_base64;

  if (direct) return cleanBase64(direct);

  const visualizations = result.visualizations || [];

  return cleanBase64(
    visualizations[index]?.image_base64 ||
    visualizations[index]?.base64 ||
    visualizations[index]?.data
  );
}

function getMimeType(result, index = 0) {
  const visualizations = result?.visualizations || [];

  return (
    result?.mime_type ||
    result?.mimeType ||
    visualizations[index]?.mime_type ||
    visualizations[index]?.mimeType ||
    "image/jpeg"
  );
}

function getVisualizationByMasker(result, maskerName) {
  const visualizations = result?.visualizations || [];
  const wanted = String(maskerName || "").toLowerCase();

  return visualizations.find(v => {
    const actual = String(v?.masker || "").toLowerCase();
    return actual === wanted;
  }) || null;
}

function getShapImageUrl(result, maskerName) {
  const v = getVisualizationByMasker(result, maskerName);
  return fixUrl(v?.image_url || null);
}

function getShapImageBase64(result, maskerName) {
  const v = getVisualizationByMasker(result, maskerName);

  return cleanBase64(
    v?.image_base64 ||
    v?.base64 ||
    v?.data
  );
}

function getShapMimeType(result, maskerName) {
  const v = getVisualizationByMasker(result, maskerName);

